// LAYER 1: Deduplizierung via BoW Similarity
const all = $input.all().map(i => i.json);
const raw = all[0]?.raw_data || [];
function bow(text) {
  const words = (text || '').toLowerCase().split(/[^\wäöüß]+/).filter(w => w.length > 3);
  const map = {};
  for (const w of words) map[w] = (map[w] || 0) + 1;
  return map;
}
function cosine(a, b) {
  const keys = new Set([...Object.keys(a), ...Object.keys(b)]);
  let dot = 0, na = 0, nb = 0;
  for (const k of keys) {
    const va = a[k] || 0, vb = b[k] || 0;
    dot += va * vb;
    na += va * va;
    nb += vb * vb;
  }
  return dot / (Math.sqrt(na) * Math.sqrt(nb) || 1);
}
const clusters = [];
const used = new Set();
for (let i = 0; i < raw.length; i++) {
  if (used.has(i)) continue;
  const cluster = [raw[i]];
  const bowi = bow(raw[i].title + ' ' + raw[i].body);
  for (let j = i + 1; j < raw.length; j++) {
    if (used.has(j)) continue;
    const bowj = bow(raw[j].title + ' ' + raw[j].body);
    if (cosine(bowi, bowj) > 0.65) {
      cluster.push(raw[j]);
      used.add(j);
    }
  }
  clusters.push({
    items: cluster,
    title: cluster[0].title,
    total_upvotes: cluster.reduce((s, c) => s + (c.upvotes || 0), 0),
    total_comments: cluster.reduce((s, c) => s + (c.comments || 0), 0),
    sources: [...new Set(cluster.map(c => c.source))],
    age_hours: Math.max(...cluster.map(c => {
      const diff = (Date.now() - new Date(c.created).getTime()) / 3600000;
      return diff;
    }))
  });
  used.add(i);
}
return [{
  json: {
    clusters: clusters.slice(0, 80),
    cluster_count: clusters.length,
    dedup_timestamp: new Date().toISOString()
  }
}];

// LAYER 2: Engagement Scoring
const clusters = $input.all()[0].json.clusters;
const scored = clusters.map(c => {
  const upvotes = c.total_upvotes;
  const comments = c.total_comments;
  const crossPlatform = c.sources.length;
  const age = Math.max(c.age_hours, 1);
  const score = ((upvotes * 1.0) + (comments * 2.5) + (crossPlatform * 50)) / age;
  return { ...c, engagement_score: Math.round(score * 100) / 100 };
}).filter(c => c.engagement_score > 15)
  .sort((a, b) => b.engagement_score - a.engagement_score)
  .slice(0, 30);
return [{json: {high_engagement: scored, count: scored.length}}];

// LAYER 4+5: Final Scoring
const gaps = $input.all().map(i => i.json);
const finals = gaps.map(g => {
  const engagement = g.engagement_score || 5;
  const gapScore = g.gap_score || 5;
  const monetization = g.monetization_potential || 5;
  const competition = (g.competition_score !== undefined ? g.competition_score : 5);
  const timing = (g.timing_score !== undefined ? g.timing_score : 5);
  const total = (engagement * 0.25 + gapScore * 0.30 + monetization * 0.20 + (10 - competition) * 0.15 + timing * 0.10);
  return { ...g, total_score: Math.round(total * 100) / 100 };
}).sort((a, b) => b.total_score - a.total_score);
const proceed = finals.filter(f => f.total_score > 7.0);
const queue = finals.filter(f => f.total_score > 5.0 && f.total_score <= 7.0);
return [{json: {proceed: proceed.slice(0, 3), queue: queue.slice(0, 5), discarded: finals.length - proceed.length - queue.length}}];
